import{_ as a,o as e,c as l,a4 as s}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"元素化合物详解","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Learn-Detail-002-元素化学详解-20260405.md","filePath":"chemistry/Chem-Learn-Detail-002-元素化学详解-20260405.md"}'),n={name:"chemistry/Chem-Learn-Detail-002-元素化学详解-20260405.md"};function i(r,t,p,d,o,g){return e(),l("div",null,[...t[0]||(t[0]=[s(`<h1 id="元素化合物详解" tabindex="-1">元素化合物详解 <a class="header-anchor" href="#元素化合物详解" aria-label="Permalink to &quot;元素化合物详解&quot;">​</a></h1><p><strong>板块2：金属元素 + 非金属元素 + 工业流程基础</strong></p><hr><h2 id="学习策略" tabindex="-1">学习策略 <a class="header-anchor" href="#学习策略" aria-label="Permalink to &quot;学习策略&quot;">​</a></h2><p><strong>元素化合物是化学的「词汇」</strong>：</p><ul><li>不会元素性质，就无法理解化学反应</li><li>不会写方程式，就无法做题</li><li>工业流程题的基础就是元素化合物知识</li></ul><p><strong>学习方法</strong>：</p><ol><li><strong>分类记忆</strong>：金属一条线，非金属一条线</li><li><strong>对比记忆</strong>：相似元素对比（Na vs Al vs Fe）</li><li><strong>转化关系</strong>：单质→氧化物→碱/酸→盐</li><li><strong>工业联系</strong>：关注工业生产中的应用</li></ol><hr><h2 id="第一章-金属元素" tabindex="-1">第一章：金属元素 <a class="header-anchor" href="#第一章-金属元素" aria-label="Permalink to &quot;第一章：金属元素&quot;">​</a></h2><h3 id="_1-1-钠-na-及其化合物" tabindex="-1">1.1 钠（Na）及其化合物 <a class="header-anchor" href="#_1-1-钠-na-及其化合物" aria-label="Permalink to &quot;1.1 钠（Na）及其化合物&quot;">​</a></h3><p><strong>物理性质</strong>：银白色金属，质软（小刀可切），密度小于水。</p><p><strong>化学性质</strong>（非常活泼）：</p><p><strong>与水的反应</strong>（重点）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2Na + 2H₂O = 2NaOH + H₂↑</span></span>
<span class="line"><span>现象：浮（密度小）、熔（放热）、游（气体推动）、响（反应剧烈）、红（加酚酞变红）</span></span></code></pre></div><p><strong>与氧气的反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>4Na + O₂ = 2Na₂O（常温，白色固体）</span></span>
<span class="line"><span>2Na + O₂ =△= Na₂O₂（加热，淡黄色固体，过氧化钠）</span></span></code></pre></div><p><strong>钠的化合物</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">化合物</th><th style="text-align:center;">化学式</th><th style="text-align:left;">重要性质</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:center;">氧化钠</td><td style="text-align:center;">Na₂O</td><td style="text-align:left;">碱性氧化物，与水反应生成NaOH</td><td style="text-align:left;">-</td></tr><tr><td style="text-align:center;"><strong>过氧化钠</strong></td><td style="text-align:center;"><strong>Na₂O₂</strong></td><td style="text-align:left;">强氧化性，与水/CO₂反应放出O₂</td><td style="text-align:left;">供氧剂</td></tr><tr><td style="text-align:center;">氢氧化钠</td><td style="text-align:center;">NaOH</td><td style="text-align:left;">强碱，易潮解，腐蚀性强</td><td style="text-align:left;">化工原料</td></tr><tr><td style="text-align:center;">碳酸钠</td><td style="text-align:center;">Na₂CO₃（纯碱）</td><td style="text-align:left;">碱性，热稳定性好</td><td style="text-align:left;">玻璃、造纸</td></tr><tr><td style="text-align:center;">碳酸氢钠</td><td style="text-align:center;">NaHCO₃（小苏打）</td><td style="text-align:left;">热稳定性差，受热分解</td><td style="text-align:left;">焙粉、胃药</td></tr></tbody></table><p><strong>Na₂CO₃ vs NaHCO₃对比</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">性质</th><th style="text-align:left;">Na₂CO₃</th><th style="text-align:left;">NaHCO₃</th></tr></thead><tbody><tr><td style="text-align:left;">俗称</td><td style="text-align:left;">纯碱、苏打</td><td style="text-align:left;">小苏打</td></tr><tr><td style="text-align:left;">溶解性</td><td style="text-align:left;">易溶</td><td style="text-align:left;">可溶（溶解度较小）</td></tr><tr><td style="text-align:left;">热稳定性</td><td style="text-align:left;">稳定</td><td style="text-align:left;">受热分解：2NaHCO₃ =△= Na₂CO₃ + H₂O + CO₂↑</td></tr><tr><td style="text-align:left;">与酸反应</td><td style="text-align:left;">较慢</td><td style="text-align:left;">较快</td></tr><tr><td style="text-align:left;">溶液碱性</td><td style="text-align:left;">较强</td><td style="text-align:left;">较弱</td></tr></tbody></table><hr><h3 id="_1-2-铝-al-及其化合物" tabindex="-1">1.2 铝（Al）及其化合物 <a class="header-anchor" href="#_1-2-铝-al-及其化合物" aria-label="Permalink to &quot;1.2 铝（Al）及其化合物&quot;">​</a></h3><p><strong>物理性质</strong>：银白色金属，密度小（轻金属），导电导热性好。</p><p><strong>化学性质</strong>：</p><p><strong>与酸碱都反应</strong>（两性金属）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2Al + 6HCl = 2AlCl₃ + 3H₂↑</span></span>
<span class="line"><span>2Al + 2NaOH + 2H₂O = 2NaAlO₂ + 3H₂↑</span></span></code></pre></div><p><strong>钝化</strong>：常温下，铝在浓硫酸、浓硝酸中表面形成致密氧化膜，阻止进一步反应。</p><p><strong>铝的化合物</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">化合物</th><th style="text-align:center;">化学式</th><th style="text-align:left;">性质</th><th style="text-align:left;">重要反应</th></tr></thead><tbody><tr><td style="text-align:center;">氧化铝</td><td style="text-align:center;">Al₂O₃</td><td style="text-align:left;"><strong>两性氧化物</strong></td><td style="text-align:left;">Al₂O₃ + 6HCl = 2AlCl₃ + 3H₂O<br>Al₂O₃ + 2NaOH = 2NaAlO₂ + H₂O</td></tr><tr><td style="text-align:center;">氢氧化铝</td><td style="text-align:center;">Al(OH)₃</td><td style="text-align:left;"><strong>两性氢氧化物</strong></td><td style="text-align:left;">Al(OH)₃ + 3HCl = AlCl₃ + 3H₂O<br>Al(OH)₃ + NaOH = NaAlO₂ + 2H₂O</td></tr></tbody></table><p><strong>Al³⁺、Al(OH)₃、AlO₂⁻ 的转化关系</strong>（重点）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>      Al³⁺（酸性）</span></span>
<span class="line"><span>       ↓ 加OH⁻</span></span>
<span class="line"><span>    Al(OH)₃（两性）</span></span>
<span class="line"><span>       ↓ 加OH⁻</span></span>
<span class="line"><span>      AlO₂⁻（碱性）</span></span></code></pre></div><hr><h3 id="_1-3-铁-fe-及其化合物" tabindex="-1">1.3 铁（Fe）及其化合物 <a class="header-anchor" href="#_1-3-铁-fe-及其化合物" aria-label="Permalink to &quot;1.3 铁（Fe）及其化合物&quot;">​</a></h3><p><strong>物理性质</strong>：银白色金属，有磁性，密度较大。</p><p><strong>化学性质</strong>：</p><p><strong>与不同氧化剂反应生成不同价态</strong>：</p><ul><li>弱氧化剂（HCl、CuSO₄）→ Fe²⁺</li><li>强氧化剂（Cl₂、HNO₃）→ Fe³⁺</li></ul><p><strong>典型反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Fe + 2HCl = FeCl₂ + H₂↑</span></span>
<span class="line"><span>2Fe + 3Cl₂ =△= 2FeCl₃（生成Fe³⁺）</span></span></code></pre></div><p><strong>铁的化合物</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">价态</th><th style="text-align:center;">氧化物</th><th style="text-align:center;">氢氧化物</th><th style="text-align:center;">盐</th></tr></thead><tbody><tr><td style="text-align:center;">+2</td><td style="text-align:center;">FeO（黑色）</td><td style="text-align:center;">Fe(OH)₂（白色→灰绿→红褐）</td><td style="text-align:center;">FeSO₄（浅绿色）</td></tr><tr><td style="text-align:center;">+3</td><td style="text-align:center;">Fe₂O₃（红棕色，铁锈）</td><td style="text-align:center;">Fe(OH)₃（红褐色）</td><td style="text-align:center;">FeCl₃（黄色）</td></tr></tbody></table><p><strong>Fe²⁺与Fe³⁺的转化</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Fe²⁺ ⇌ Fe³⁺</span></span>
<span class="line"><span> ↑    ↓</span></span>
<span class="line"><span>还原 氧化</span></span></code></pre></div><p><strong>检验方法</strong>：</p><ul><li>Fe³⁺：加KSCN溶液，变血红色</li><li>Fe²⁺：先加KSCN无现象，再加氯水变血红色</li></ul><hr><h2 id="第二章-非金属元素" tabindex="-1">第二章：非金属元素 <a class="header-anchor" href="#第二章-非金属元素" aria-label="Permalink to &quot;第二章：非金属元素&quot;">​</a></h2><h3 id="_2-1-氯-cl-及其化合物" tabindex="-1">2.1 氯（Cl）及其化合物 <a class="header-anchor" href="#_2-1-氯-cl-及其化合物" aria-label="Permalink to &quot;2.1 氯（Cl）及其化合物&quot;">​</a></h3><p><strong>物理性质</strong>：黄绿色气体，有毒，有刺激性气味，密度大于空气。</p><p><strong>化学性质</strong>（强氧化性）：</p><p><strong>与金属反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2Na + Cl₂ = 2NaCl（白烟）</span></span>
<span class="line"><span>2Fe + 3Cl₂ =△= 2FeCl₃（棕褐色烟）</span></span>
<span class="line"><span>Cu + Cl₂ =△= CuCl₂（棕黄色烟）</span></span></code></pre></div><p><strong>与氢气反应</strong>（爆炸）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>H₂ + Cl₂ = 2HCl（光照或点燃爆炸）</span></span></code></pre></div><p><strong>氯的化合物</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">化合物</th><th style="text-align:center;">化学式</th><th style="text-align:left;">性质</th><th style="text-align:left;">制备/用途</th></tr></thead><tbody><tr><td style="text-align:center;">氯化氢</td><td style="text-align:center;">HCl</td><td style="text-align:left;">强酸</td><td style="text-align:left;">H₂在Cl₂中燃烧</td></tr><tr><td style="text-align:center;"><strong>次氯酸</strong></td><td style="text-align:center;"><strong>HClO</strong></td><td style="text-align:left;">弱酸，强氧化性，漂白性</td><td style="text-align:left;">Cl₂ + H₂O = HCl + HClO</td></tr><tr><td style="text-align:center;">次氯酸钠</td><td style="text-align:center;">NaClO</td><td style="text-align:left;">漂白液主要成分</td><td style="text-align:left;">Cl₂ + 2NaOH = NaCl + NaClO + H₂O</td></tr><tr><td style="text-align:center;">次氯酸钙</td><td style="text-align:center;">Ca(ClO)₂</td><td style="text-align:left;">漂白粉主要成分</td><td style="text-align:left;">2Cl₂ + 2Ca(OH)₂ = CaCl₂ + Ca(ClO)₂ + 2H₂O</td></tr></tbody></table><p><strong>氯水的成分</strong>：</p><ul><li>三种分子：H₂O、Cl₂、HClO</li><li>四种离子：H⁺、Cl⁻、ClO⁻、OH⁻（极少量）</li></ul><hr><h3 id="_2-2-硫-s-及其化合物" tabindex="-1">2.2 硫（S）及其化合物 <a class="header-anchor" href="#_2-2-硫-s-及其化合物" aria-label="Permalink to &quot;2.2 硫（S）及其化合物&quot;">​</a></h3><p><strong>硫的化合物转化关系</strong>（重点）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       H₂S（-2价）</span></span>
<span class="line"><span>         ↓ 氧化</span></span>
<span class="line"><span>         S（0价）</span></span>
<span class="line"><span>         ↓ 氧化</span></span>
<span class="line"><span>       SO₂（+4价）</span></span>
<span class="line"><span>         ↓ 氧化</span></span>
<span class="line"><span>       SO₃（+6价）</span></span>
<span class="line"><span>         ↓ +H₂O</span></span>
<span class="line"><span>       H₂SO₄（+6价）</span></span></code></pre></div><p><strong>SO₂的性质</strong>（还原性为主）：</p><ul><li>酸性氧化物：SO₂ + H₂O ⇌ H₂SO₃</li><li>还原性：2SO₂ + O₂ ⇌ 2SO₃（催化剂，加热）</li><li>漂白性：能使品红溶液褪色（可逆，加热恢复）</li></ul><p><strong>浓硫酸的性质</strong>：</p><ul><li>吸水性：干燥剂</li><li>脱水性：使有机物碳化</li><li>强氧化性：Cu + 2H₂SO₄(浓) =△= CuSO₄ + SO₂↑ + 2H₂O</li></ul><hr><h3 id="_2-3-氮-n-及其化合物" tabindex="-1">2.3 氮（N）及其化合物 <a class="header-anchor" href="#_2-3-氮-n-及其化合物" aria-label="Permalink to &quot;2.3 氮（N）及其化合物&quot;">​</a></h3><p><strong>氮的化合物转化关系</strong>（重点）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>      NH₃（-3价）</span></span>
<span class="line"><span>         ↓ 氧化</span></span>
<span class="line"><span>         N₂（0价）</span></span>
<span class="line"><span>         ↓ 氧化</span></span>
<span class="line"><span>       NO（+2价）</span></span>
<span class="line"><span>         ↓ +O₂</span></span>
<span class="line"><span>       NO₂（+4价）</span></span>
<span class="line"><span>         ↓ +H₂O</span></span>
<span class="line"><span>       HNO₃（+5价）</span></span></code></pre></div><p><strong>NH₃的性质</strong>：</p><ul><li>极易溶于水（1:700）</li><li>碱性气体：NH₃ + H₂O ⇌ NH₃·H₂O ⇌ NH₄⁺ + OH⁻</li><li>检验：使湿润的红色石蕊试纸变蓝</li></ul><p><strong>硝酸（HNO₃）的性质</strong>（重点）：</p><ul><li>强酸性</li><li><strong>强氧化性</strong>（浓硝酸、稀硝酸都有氧化性）</li><li>与金属反应不生成H₂</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cu + 4HNO₃(浓) = Cu(NO₃)₂ + 2NO₂↑ + 2H₂O</span></span>
<span class="line"><span>3Cu + 8HNO₃(稀) = 3Cu(NO₃)₂ + 2NO↑ + 4H₂O</span></span></code></pre></div><hr><h2 id="第三章-元素化合物综合应用" tabindex="-1">第三章：元素化合物综合应用 <a class="header-anchor" href="#第三章-元素化合物综合应用" aria-label="Permalink to &quot;第三章：元素化合物综合应用&quot;">​</a></h2><h3 id="_3-1-元素推断题突破口" tabindex="-1">3.1 元素推断题突破口 <a class="header-anchor" href="#_3-1-元素推断题突破口" aria-label="Permalink to &quot;3.1 元素推断题突破口&quot;">​</a></h3><p><strong>特征颜色</strong>：</p><ul><li>淡黄色：Na₂O₂、S</li><li>红棕色：Fe₂O₃、NO₂</li><li>红褐色：Fe(OH)₃</li><li>浅绿色：Fe²⁺溶液</li><li>黄色：Fe³⁺溶液</li><li>黄绿色：Cl₂</li></ul><p><strong>特征反应</strong>：</p><ul><li>使品红褪色 → SO₂或Cl₂</li><li>使KSCN变红 → Fe³⁺</li><li>与酸碱都反应 → Al、Al₂O₃、Al(OH)₃</li></ul><h3 id="_3-2-工业流程基础" tabindex="-1">3.2 工业流程基础 <a class="header-anchor" href="#_3-2-工业流程基础" aria-label="Permalink to &quot;3.2 工业流程基础&quot;">​</a></h3><p><strong>氯碱工业</strong>（电解饱和食盐水）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2NaCl + 2H₂O =电解= 2NaOH + H₂↑ + Cl₂↑</span></span></code></pre></div><p><strong>硫酸工业</strong>（接触法）：</p><ol><li>4FeS₂ + 11O₂ = 2Fe₂O₃ + 8SO₂</li><li>2SO₂ + O₂ ⇌ 2SO₃（V₂O₅催化，450℃）</li><li>SO₃ + H₂O = H₂SO₄</li></ol><p><strong>硝酸工业</strong>（氨氧化法）：</p><ol><li>4NH₃ + 5O₂ = 4NO + 6H₂O（Pt催化，800℃）</li><li>2NO + O₂ = 2NO₂</li><li>3NO₂ + H₂O = 2HNO₃ + NO</li></ol><hr><h2 id="faq-常见错误与解答" tabindex="-1">FAQ（常见错误与解答） <a class="header-anchor" href="#faq-常见错误与解答" aria-label="Permalink to &quot;FAQ（常见错误与解答）&quot;">​</a></h2><h3 id="q1-元素化合物性质太多记不住怎么办" tabindex="-1">Q1：元素化合物性质太多记不住怎么办？ <a class="header-anchor" href="#q1-元素化合物性质太多记不住怎么办" aria-label="Permalink to &quot;Q1：元素化合物性质太多记不住怎么办？&quot;">​</a></h3><p><strong>A</strong>：用「转化关系图」记忆：</p><ul><li>每种元素画一条线：单质→氧化物→碱/酸→盐</li><li>记住特征反应和颜色</li><li>不要死记所有反应，掌握规律更重要</li></ul><h3 id="q2-fe2-和fe3-怎么区分和检验" tabindex="-1">Q2：Fe²⁺和Fe³⁺怎么区分和检验？ <a class="header-anchor" href="#q2-fe2-和fe3-怎么区分和检验" aria-label="Permalink to &quot;Q2：Fe²⁺和Fe³⁺怎么区分和检验？&quot;">​</a></h3><p><strong>A</strong>：</p><ul><li>Fe³⁺：加KSCN，溶液变血红色（最直接）</li><li>Fe²⁺：加KSCN无现象，再加氯水（或H₂O₂）变血红色</li><li>注意：Fe²⁺溶液是浅绿色，Fe³⁺溶液是黄色</li></ul><h3 id="q3-so2和cl2的漂白性有什么区别" tabindex="-1">Q3：SO₂和Cl₂的漂白性有什么区别？ <a class="header-anchor" href="#q3-so2和cl2的漂白性有什么区别" aria-label="Permalink to &quot;Q3：SO₂和Cl₂的漂白性有什么区别？&quot;">​</a></h3><p><strong>A</strong>：</p><ul><li>SO₂：与有色物质化合，<strong>可逆</strong>（加热恢复），漂白品红</li><li>Cl₂：HClO氧化有色物质，<strong>不可逆</strong>，漂白范围更广</li><li>注意：SO₂使溴水、KMnO₄褪色是因为还原性，不是漂白性</li></ul><h3 id="q4-工业流程题怎么入手" tabindex="-1">Q4：工业流程题怎么入手？ <a class="header-anchor" href="#q4-工业流程题怎么入手" aria-label="Permalink to &quot;Q4：工业流程题怎么入手？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>先看原料和产品，明确转化目标</li><li>关注「循环利用」的物质</li><li>熟悉常见操作：粉碎（增大接触面积）、焙烧、酸浸、过滤、结晶</li><li>结合元素化合物知识分析每步反应</li></ol><hr><h2 id="文档信息" tabindex="-1">文档信息 <a class="header-anchor" href="#文档信息" aria-label="Permalink to &quot;文档信息&quot;">​</a></h2><p><strong>文档编号</strong>: Chem-Learn-Detail-002<br><strong>板块</strong>: 元素化合物<br><strong>版本</strong>: V1.0<br><strong>编制日期</strong>: 2026-04-05<br><strong>配套文档</strong>: Chem-Learn-Method-001</p><hr><p><em>元素化合物是化学学习的基础，务必打牢。建议每学完一种元素，画一张转化关系图。</em></p>`,109)])])}const u=a(n,[["render",i]]);export{c as __pageData,u as default};
